1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_BLOCK_PREMIUM: Record<string, number> = {
14	  rune: 60,
15	  moonstone: 60,
16	};
17	
18	function calculateBasePremium(items: any[]): number {
19	  const groups: Record<string, any[]> = {};
20	  for (const item of items) {
21	    if (!groups[item.type]) groups[item.type] = [];
22	    groups[item.type].push(item);
23	  }
24	
25	  let total = 0;
26	  for (const type of Object.keys(groups)) {
27	    const group = groups[type];
28	    if (group.length === 3 && COMPONENT_BLOCK_PREMIUM[type] !== undefined) {
29	      total += COMPONENT_BLOCK_PREMIUM[type];
30	    } else {
31	      total += group.length * BASE_PREMIUMS[type];
32	    }
33	  }
34	  return total;
35	}
36	
37	function calculateItemSurcharges(items: any[]): number {
38	  let surcharges = 0;
39	  for (const item of items) {
40	    if (item.cursed) {
41	      surcharges += BASE_PREMIUMS[item.type] * 0.5;
42	    }
43	    if (item.enchantment >= 5) {
44	      surcharges += BASE_PREMIUMS[item.type] * 0.3;
45	    }
46	  }
47	  return surcharges;
48	}
49	
50	function calculatePremium(items: any[]): number {
51	  const basePremium = calculateBasePremium(items);
52	  const itemSurcharges = calculateItemSurcharges(items);
53	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
54	  return Math.ceil(basePremium + itemSurcharges + firstInsuranceSurcharge + PROCESSING_FEE);
55	}
56	
57	export function processScenario(scenario: any): unknown {
58	  const { items } = scenario.steps[0];
59	  const premium = calculatePremium(items);
60	
61	  return { results: [{ premium }] };
62	}
