function calculateItemSurcharges(items: any[]): number {
  let surcharges = 0;
  for (const item of items) {
    const itemBase = BASE_PREMIUMS[item.type];
    if (item.cursed) {
      surcharges += itemBase * 0.5;
    }
    if (item.enchantment >= 5) {
      surcharges += itemBase * 0.3;
    }
  }
  return surcharges;
}
